import os

def delete_file(filename):
    if os.path.isfile('./uploads/{}'.format(filename)):
        os.remove('./uploads/{}'.format(filename))
        return 'File {} has been deleted.'.format(filename)
    else:
        return 'File {} not found.'.format(filename)